package com.riderental.myriderental.db;

import com.riderental.myriderental.util.DBConnection;
import org.mindrot.jbcrypt.BCrypt;

import java.sql.Connection;
import java.sql.PreparedStatement;
import java.sql.ResultSet;
import java.sql.SQLException;
import java.util.logging.Level;
import java.util.logging.Logger;

/**
 * Seeds a default admin user at application startup.
 *
 * Notes:
 * - Uses existing DBConnection for obtaining JDBC connections.
 * - Uses jBCrypt for password hashing.
 * - Idempotent: checks for existing email before inserting.
 */
public class AdminSeeder {

    private static final Logger LOGGER = Logger.getLogger(AdminSeeder.class.getName());
    private static final String ADMIN_EMAIL = "admin@gmail.com";
    private static final String DEFAULT_PASSWORD = "admin123";
    private static final int BCRYPT_LOG_ROUNDS = 12;

    private AdminSeeder() {
        // utility class
    }

    public static void seed() {
        try (Connection conn = DBConnection.getConnection()) {
            // Use a transaction to avoid partial writes
            boolean previousAutoCommit = conn.getAutoCommit();
            conn.setAutoCommit(false);
            try {
                if (adminExists(conn)) {
                    LOGGER.info("Admin user already exists. Skipping seeding.");
                    conn.commit();
                    return;
                }

                String hashed = BCrypt.hashpw(DEFAULT_PASSWORD, BCrypt.gensalt(BCRYPT_LOG_ROUNDS));

                String insertSql = "INSERT INTO users (fullName, email, password, phoneNumber, address, profileImagePath, role, trustScore, accountStatus) VALUES (?, ?, ?, NULL, NULL, NULL, ?, ?, ?)";
                try (PreparedStatement ps = conn.prepareStatement(insertSql)) {
                    ps.setString(1, "Admin User");
                    ps.setString(2, ADMIN_EMAIL);
                    ps.setString(3, hashed);
                    ps.setString(4, "ADMIN");
                    ps.setDouble(5, 0);
                    ps.setString(6, "ACTIVE");

                    int rows = ps.executeUpdate();
                    if (rows == 1) {
                        LOGGER.info("Admin user seeded successfully.");
                    } else {
                        LOGGER.warning("Admin seeding executed but affected " + rows + " rows.");
                    }
                }

                conn.commit();
            } catch (SQLException ex) {
                try {
                    conn.rollback();
                } catch (SQLException rollbackEx) {
                    LOGGER.log(Level.SEVERE, "Rollback failed after seeding error", rollbackEx);
                }
                throw ex;
            } finally {
                conn.setAutoCommit(previousAutoCommit);
            }
        } catch (SQLException ex) {
            LOGGER.log(Level.SEVERE, "Failed to seed admin user", ex);
        }
    }

    private static boolean adminExists(Connection conn) throws SQLException {
        String checkSql = "SELECT 1 FROM users WHERE email = ? LIMIT 1";
        try (PreparedStatement ps = conn.prepareStatement(checkSql)) {
            ps.setString(1, ADMIN_EMAIL);
            try (ResultSet rs = ps.executeQuery()) {
                return rs.next();
            }
        }
    }
}

package com.riderental.myriderental.config;

import com.mysql.cj.jdbc.AbandonedConnectionCleanupThread;
import jakarta.servlet.ServletContextEvent;
import jakarta.servlet.ServletContextListener;
import jakarta.servlet.annotation.WebListener;

import java.sql.Driver;
import java.sql.DriverManager;
import java.sql.SQLException;
import java.util.Enumeration;

@WebListener
public class AppStartListener implements ServletContextListener {

    @Override
    public void contextInitialized(ServletContextEvent sce) {
        FlywayRunner.migrate();
    }

    @Override
    public void contextDestroyed(ServletContextEvent sce) {
        cleanupJdbcDrivers();
        AbandonedConnectionCleanupThread.checkedShutdown();
    }

    private void cleanupJdbcDrivers() {
        ClassLoader webAppClassLoader = Thread.currentThread().getContextClassLoader();
        Enumeration<Driver> drivers = DriverManager.getDrivers();

        while (drivers.hasMoreElements()) {
            Driver driver = drivers.nextElement();
            if (driver.getClass().getClassLoader() == webAppClassLoader) {
                try {
                    DriverManager.deregisterDriver(driver);
                } catch (SQLException ignored) {
                    // Ignore cleanup errors during shutdown.
                }
            }
        }
    }
}

package com.riderental.myriderental.config;

import jakarta.servlet.ServletContext;
import jakarta.servlet.ServletContextEvent;
import jakarta.servlet.ServletContextListener;
import jakarta.servlet.annotation.WebListener;

import java.lang.reflect.Method;
import java.sql.Driver;
import java.sql.DriverManager;
import java.sql.SQLException;
import java.util.Enumeration;
import java.util.logging.Level;
import java.util.logging.Logger;

@WebListener
public class AppStartListener implements ServletContextListener {

    private static final Logger LOGGER = Logger.getLogger(AppStartListener.class.getName());

    @Override
    public void contextInitialized(ServletContextEvent sce) {
        ServletContext context = sce.getServletContext();
        try {
            FlywayRunner.migrate();
            context.log("Flyway migration completed.");
        } catch (RuntimeException ex) {
            // Keep app deployable even if migration fails; error is logged for investigation.
            context.log("Flyway migration failed during startup. Application will start without auto-migration.", ex);
        }
    }

    @Override
    public void contextDestroyed(ServletContextEvent sce) {
        cleanupJdbcDrivers();
        shutdownMysqlCleanupThread();
    }

    private void cleanupJdbcDrivers() {
        ClassLoader webAppClassLoader = AppStartListener.class.getClassLoader();
        Enumeration<Driver> drivers = DriverManager.getDrivers();

        while (drivers.hasMoreElements()) {
            Driver driver = drivers.nextElement();
            if (driver.getClass().getClassLoader() == webAppClassLoader) {
                try {
                    DriverManager.deregisterDriver(driver);
                } catch (SQLException ex) {
                    LOGGER.log(Level.FINE, "Could not deregister JDBC driver during shutdown: " + driver, ex);
                }
            }
        }
    }

    private void shutdownMysqlCleanupThread() {
        try {
            Class<?> cleanupThreadClass = Class.forName("com.mysql.cj.jdbc.AbandonedConnectionCleanupThread");
            Method checkedShutdown = cleanupThreadClass.getMethod("checkedShutdown");
            checkedShutdown.invoke(null);
        } catch (ClassNotFoundException ignored) {
            // MySQL driver not present in this classloader; nothing to shut down.
        } catch (Exception ex) {
            LOGGER.log(Level.FINE, "MySQL cleanup thread shutdown was not completed.", ex);
        }
    }
}
